mapper.select:
SELECT * FROM ( SELECT ROWNUM AS rn, inner_q.* FROM ( SELECT e2.empId, e2.name, e2.profilePhoto, e2.deptCode, cc_dept.codeName AS deptName, e2.gradeCode, cc_rank.codeName AS gradeName, e1.empStatusCode, cc_stat.codeName AS empStatusName, cr.roomId, CASE WHEN cm_last.msgType = 'FILE' THEN cf_last.originalName ELSE cm_last.content END AS lastMessage, cm_last.msgType AS lastMessageType, cm_last.senderId AS lastSenderId, TO_CHAR(cm_last.sentAt, 'YYYY-MM-DD"T"HH24:MI:SS') AS lastMessageAt, NVL(unread.cnt, 0) AS unreadCount FROM employee2 e2 /* ① 재직 정보 */ JOIN employee1 e1 ON e1.empId = e2.empId /* ② 공통코드 */ LEFT JOIN commoncode cc_dept ON cc_dept.codeGroup = 'DEPT' AND cc_dept.code = e2.deptCode LEFT JOIN commoncode cc_rank ON cc_rank.codeGroup = 'RANK' AND cc_rank.code = e2.gradeCode LEFT JOIN commoncode cc_stat ON cc_stat.codeGroup = 'EMPSTATUS' AND cc_stat.code = e1.empStatusCode /* ③ 두 사람 간 채팅방 */ LEFT JOIN chatroom cr ON ( (cr.userAid = #{myEmpId} AND cr.userBid = e2.empId) OR (cr.userBid = #{myEmpId} AND cr.userAid = e2.empId) ) AND cr.status = 'ACTIVE' /* ④ 가장 최근 메시지 */ LEFT JOIN chatmessage cm_last ON cm_last.messageId = ( SELECT MAX(messageId) FROM chatmessage WHERE roomId = cr.roomId AND status != 'DELETED' ) LEFT JOIN chatfile cf_last ON cf_last.messageId = cm_last.messageId /* ⑤ 미읽음 카운트 */ LEFT JOIN ( SELECT roomId, COUNT(*) AS cnt FROM chatmessage WHERE senderId != #{myEmpId} AND isRead = 'N' AND status != 'DELETED' GROUP BY roomId ) unread ON unread.roomId = cr.roomId /* ⑥ WHERE — 반드시 모든 JOIN 뒤에 위치 (Oracle 문법) */ WHERE e2.empId != #{myEmpId} AND e1.enabled = 1 AND EXISTS ( SELECT 1 FROM empProject ep_other JOIN empProject ep_me ON ep_me.projectId = ep_other.projectId AND ep_me.empId = #{myEmpId} WHERE ep_other.empId = e2.empId
AND ep_other.projectId = #{projectId}
)
AND ( LOWER(e2.name) LIKE '%' || LOWER(#{keyword}) || '%' OR LOWER(e2.empId) LIKE '%' || LOWER(#{keyword}) || '%' )
ORDER BY NVL(unread.cnt, 0) DESC, -- 미읽음 수 CASE WHEN cm_last.senderId != #{myEmpId} THEN cm_last.sentAt END DESC, -- 최근 받은 메시지 CASE WHEN cm_last.senderId = #{myEmpId} THEN cm_last.sentAt END DESC, -- 최근 보낸 메시지 NLSSORT(e2.name, 'NLS_SORT=BINARY_AI') ASC -- 이름 가나다 ) inner_q ) WHERE rn > #{offset} AND rn <= #{offset} + #{size}

SELECT COUNT(*)
FROM chatroommember
WHERE roomId = #{roomId}
  AND empId  = #{empId}

mapper.update:
UPDATE chatroom
SET lastMessageAt = SYSTIMESTAMP
WHERE roomId = #{roomId}

UPDATE chatmessage
SET isRead = 'Y'
WHERE roomId  = #{roomId}
  AND senderId != #{empId}
  AND isRead  = 'N'

UPDATE chatmessage
SET isRead = 'Y'
WHERE messageId = #{messageId}

